     1→import browser from 'webextension-polyfill';
     2→
     3→import { StorageKeys } from '@/core/types/common';
     4→
     5→import { type AppLanguage, normalizeLanguage } from './language';
     6→import { TRANSLATIONS, type TranslationKey, isTranslationKey } from './translations';
     7→
     8→type StorageAreaName = 'sync' | 'local';
     9→
    10→const readStorageValue = async (area: StorageAreaName): Promise<unknown> => {
    11→  try {
    12→    const storageArea = browser.storage?.[area];
    13→    if (storageArea?.get) {
    14→      const result = await storageArea.get(StorageKeys.LANGUAGE);
    15→      if (result && typeof result === 'object') {
    16→        return (result as Record<string, unknown>)[StorageKeys.LANGUAGE];
    17→      }
    18→    }
    19→  } catch {
    20→    // Fall through to chrome.* fallback below.
    21→  }
    22→
    23→  try {
    24→    const chromeStorage = chrome?.storage?.[area];
    25→    if (!chromeStorage?.get) return null;
    26→    return await new Promise<unknown>((resolve) => {
    27→      chromeStorage.get(StorageKeys.LANGUAGE, (result) => {
    28→        if (result && typeof result === 'object') {
    29→          resolve((result as Record<string, unknown>)[StorageKeys.LANGUAGE]);
    30→        } else {
    31→          resolve(null);
    32→        }
    33→      });
    34→    });
    35→  } catch {
    36→    return null;
    37→  }
    38→};
    39→
    40→const getStoredLanguage = async (): Promise<string | null> => {
    41→  const syncValue = await readStorageValue('sync');
    42→  if (typeof syncValue === 'string') return syncValue;
    43→  const localValue = await readStorageValue('local');
    44→  if (typeof localValue === 'string') return localValue;
    45→  return null;
    46→};
    47→
    48→/**
    49→ * Get the current language preference
    50→ * 1. First check user's saved preference in storage
    51→ * 2. Fall back to browser UI language
    52→ * 3. Default to English
    53→ */
    54→export async function getCurrentLanguage(): Promise<AppLanguage> {
    55→  const stored = await getStoredLanguage();
    56→  if (typeof stored === 'string') {
    57→    return normalizeLanguage(stored);
    58→  }
    59→
    60→  // Fall back to browser UI language
    61→  try {
    62→    const browserLang = browser.i18n.getUILanguage();
    63→    return normalizeLanguage(browserLang);
    64→  } catch {
    65→    return 'en';
    66→  }
    67→}
    68→
    69→/**
    70→ * Get translation for a key using the current language preference
    71→ * This function works in both React and non-React contexts (e.g., content scripts)
    72→ */
    73→export async function getTranslation(key: TranslationKey): Promise<string> {
    74→  const language = await getCurrentLanguage();
    75→  return TRANSLATIONS[language][key] ?? TRANSLATIONS.en[key] ?? key;
    76→}
    77→
    78→/**
    79→ * Get translation synchronously using cached language
    80→ * This is less accurate but faster for scenarios where async is not possible
    81→ */
    82→let cachedLanguage: AppLanguage | null = null;
    83→
    84→export function getTranslationSync(key: TranslationKey): string {
    85→  const language = cachedLanguage || 'en';
    86→  return TRANSLATIONS[language][key] ?? TRANSLATIONS.en[key] ?? key;
    87→}
    88→
    89→export function getTranslationSyncUnsafe(key: string): string {
    90→  if (!isTranslationKey(key)) return key;
    91→  return getTranslationSync(key);
    92→}
    93→
    94→/**
    95→ * Initialize the i18n system and cache the current language
    96→ * Should be called early in the application lifecycle
    97→ */
    98→export async function initI18n(): Promise<void> {
    99→  cachedLanguage = await getCurrentLanguage();
   100→
   101→  // Listen for language changes
   102→  browser.storage.onChanged.addListener((changes, areaName) => {
   103→    const next = changes[StorageKeys.LANGUAGE]?.newValue;
   104→    if ((areaName === 'sync' || areaName === 'local') && typeof next === 'string') {
   105→      cachedLanguage = normalizeLanguage(next);
   106→    }
   107→  });
   108→}
   109→
   110→/**
   111→ * Immediately update the cached language value.
   112→ * This should be called after setting the language in storage to ensure
   113→ * synchronous translation calls use the new language immediately,
   114→ * avoiding race conditions with the async storage.onChanged listener.
   115→ */
   116→export function setCachedLanguage(lang: AppLanguage): void {
   117→  cachedLanguage = lang;
   118→}
   119→
   120→/**
   121→ * Create a translator function that uses cached language
   122→ * This is useful for classes that need a simple t() function
   123→ */
   124→export function createTranslator(): (key: string) => string {
   125→  return (key: string) => getTranslationSyncUnsafe(key);
   126→}
   127→

