     1→import arMessages from '@locales/ar/messages.json';
     2→import enMessages from '@locales/en/messages.json';
     3→import esMessages from '@locales/es/messages.json';
     4→import frMessages from '@locales/fr/messages.json';
     5→import jaMessages from '@locales/ja/messages.json';
     6→import koMessages from '@locales/ko/messages.json';
     7→import ptMessages from '@locales/pt/messages.json';
     8→import ruMessages from '@locales/ru/messages.json';
     9→import zhMessages from '@locales/zh/messages.json';
    10→import zhTWMessages from '@locales/zh_TW/messages.json';
    11→
    12→import type { AppLanguage } from './language';
    13→
    14→type RawLocaleMessages = typeof enMessages;
    15→
    16→// Compile-time guarantee: every supported language must provide at least the same keys as English.
    17→const rawMessagesByLanguage = {
    18→  en: enMessages,
    19→  zh: zhMessages,
    20→  zh_TW: zhTWMessages,
    21→  ja: jaMessages,
    22→  fr: frMessages,
    23→  es: esMessages,
    24→  pt: ptMessages,
    25→  ar: arMessages,
    26→  ru: ruMessages,
    27→  ko: koMessages,
    28→} satisfies Record<AppLanguage, RawLocaleMessages>;
    29→
    30→export type TranslationKey = keyof RawLocaleMessages;
    31→export type Translation = Record<TranslationKey, string>;
    32→
    33→function extractTranslations<M extends Record<string, { message: string }>>(
    34→  raw: M,
    35→): Record<keyof M, string> {
    36→  const out = {} as Record<keyof M, string>;
    37→  for (const key of Object.keys(raw) as Array<keyof M>) {
    38→    out[key] = raw[key].message;
    39→  }
    40→  return out;
    41→}
    42→
    43→export const TRANSLATIONS: Record<AppLanguage, Translation> = {
    44→  en: extractTranslations(rawMessagesByLanguage.en),
    45→  zh: extractTranslations(rawMessagesByLanguage.zh),
    46→  zh_TW: extractTranslations(rawMessagesByLanguage.zh_TW),
    47→  ja: extractTranslations(rawMessagesByLanguage.ja),
    48→  fr: extractTranslations(rawMessagesByLanguage.fr),
    49→  es: extractTranslations(rawMessagesByLanguage.es),
    50→  pt: extractTranslations(rawMessagesByLanguage.pt),
    51→  ar: extractTranslations(rawMessagesByLanguage.ar),
    52→  ru: extractTranslations(rawMessagesByLanguage.ru),
    53→  ko: extractTranslations(rawMessagesByLanguage.ko),
    54→};
    55→
    56→export function isTranslationKey(value: string): value is TranslationKey {
    57→  return value in rawMessagesByLanguage.en;
    58→}
    59→

