     1→export const APP_LANGUAGES = [
     2→  'en',
     3→  'zh',
     4→  'zh_TW',
     5→  'ja',
     6→  'fr',
     7→  'es',
     8→  'pt',
     9→  'ar',
    10→  'ru',
    11→  'ko',
    12→] as const;
    13→
    14→export type AppLanguage = (typeof APP_LANGUAGES)[number];
    15→
    16→export const APP_LANGUAGE_LABELS: Record<AppLanguage, string> = {
    17→  en: 'English',
    18→  zh: '简体中文',
    19→  zh_TW: '繁體中文',
    20→  ja: '日本語',
    21→  fr: 'Français',
    22→  es: 'Español',
    23→  pt: 'Português',
    24→  ar: 'العربية',
    25→  ru: 'Русский',
    26→  ko: '한국어',
    27→};
    28→
    29→export function isAppLanguage(value: unknown): value is AppLanguage {
    30→  return typeof value === 'string' && (APP_LANGUAGES as readonly string[]).includes(value);
    31→}
    32→
    33→export function normalizeLanguage(lang: string | undefined | null): AppLanguage {
    34→  if (!lang) return 'en';
    35→  const lower = lang.toLowerCase();
    36→  // Check for Traditional Chinese first (zh-TW, zh-HK, zh-Hant)
    37→  if (
    38→    lower.startsWith('zh-tw') ||
    39→    lower.startsWith('zh_tw') ||
    40→    lower.startsWith('zh-hk') ||
    41→    lower.includes('hant')
    42→  )
    43→    return 'zh_TW';
    44→  // Then check for Simplified Chinese
    45→  if (lower.startsWith('zh')) return 'zh';
    46→  if (lower.startsWith('ja')) return 'ja';
    47→  if (lower.startsWith('fr')) return 'fr';
    48→  if (lower.startsWith('es')) return 'es';
    49→  if (lower.startsWith('pt')) return 'pt';
    50→  if (lower.startsWith('ar')) return 'ar';
    51→  if (lower.startsWith('ru')) return 'ru';
    52→  if (lower.startsWith('ko')) return 'ko';
    53→  return 'en';
    54→}
    55→
    56→export function getNextLanguage(current: AppLanguage): AppLanguage {
    57→  const idx = APP_LANGUAGES.indexOf(current);
    58→  if (idx < 0) return 'en';
    59→  return APP_LANGUAGES[(idx + 1) % APP_LANGUAGES.length];
    60→}
    61→

